mapper.select:
SELECT

FROM cart_item c
LEFT JOIN product p ON p.id = c.product_id
WHERE c.user_id = #{userId}
  AND c.id = #{id}

SELECT id, user_id, product_id, quantity, selected, create_time, update_time
FROM cart_item
WHERE user_id = #{userId}
  AND id = #{id}

SELECT id, user_id, product_id, quantity, selected, create_time, update_time
FROM cart_item
WHERE user_id = #{userId}
  AND product_id = #{productId}
LIMIT 1

mapper.update:
UPDATE cart_item
SET quantity = #{quantity},
    selected = #{selected}
WHERE user_id = #{userId}
  AND id = #{id}

mapper.delete:
DELETE FROM cart_item
WHERE user_id = #{userId}
  AND id = #{id}

DELETE FROM cart_item
WHERE user_id = #{userId}
  AND selected = 1

DELETE FROM cart_item
WHERE user_id = #{userId}
  AND id IN

    #{id}
